import os
import json
import argparse
import numpy as np
from collections import deque
from cogniplan_env import ExplorationEnv

def get_action(obs):
    if not obs["neighbors"]:
        return None

    nodes = obs["nodes"]
    robot_pos = tuple(np.round(obs["robot_pos"], 2))
    graph = {}
    for node in nodes:
        coords = tuple(np.round(node["coords"], 2))
        graph[coords] = {
            "utility": node["utility"],
            "visited": node.get("visited", False),
            "neighbors": [tuple(np.round(n, 2)) for n in node["neighbors"]]
        }

    if robot_pos not in graph:
        if not graph: return obs["neighbors"][0]
        closest_node = min(graph.keys(), key=lambda k: (k[0]-robot_pos[0])**2 + (k[1]-robot_pos[1])**2)
        robot_pos = closest_node

    queue = deque()
    visited = set([robot_pos])
    valid_actions = [tuple(np.round(n, 2)) for n in obs["neighbors"]]
    node_info = {} 

    for action in valid_actions:
        if action in graph:
            queue.append((action, action, 1))
            visited.add(action)
            node_info[action] = (action, 1)

    while queue:
        curr, first_step, dist = queue.popleft()
        for nxt in graph[curr]["neighbors"]:
            if nxt not in visited and nxt in graph:
                visited.add(nxt)
                queue.append((nxt, first_step, dist + 1))
                node_info[nxt] = (first_step, dist + 1)

    best_utility_action = None
    best_utility_dist = float('inf')
    max_utility_at_best_dist = -1

    best_unvisited_action = None
    best_unvisited_dist = float('inf')

    for node_coords, info in graph.items():
        if node_coords in node_info:
            first_step, dist = node_info[node_coords]
            utility = info["utility"]
            is_visited = info["visited"]

            if not is_visited:
                if dist < best_unvisited_dist:
                    best_unvisited_dist = dist
                    best_unvisited_action = first_step

            if utility > 0:
                if dist < best_utility_dist:
                    best_utility_dist = dist
                    best_utility_action = first_step
                    max_utility_at_best_dist = utility
                elif dist == best_utility_dist:
                    if utility > max_utility_at_best_dist:
                        best_utility_action = first_step
                        max_utility_at_best_dist = utility

    chosen_action = best_utility_action if best_utility_action else best_unvisited_action
    if not chosen_action: chosen_action = valid_actions[0]

    for n in obs["neighbors"]:
        if tuple(np.round(n, 2)) == chosen_action:
            return n
    return obs["neighbors"][0]

def main():
    parser = argparse.ArgumentParser()
    parser.add_argument("--data_path", type=str, required=True)
    parser.add_argument("--checkpoint", type=str, required=True)
    parser.add_argument("--output", type=str, required=True)
    args = parser.parse_args()

    eval_config_path = os.path.join(args.data_path, "eval_config.json")
    with open(eval_config_path, "r") as f:
        eval_config = json.load(f)

    maps_eval_dir = os.path.join(args.data_path, "maps_eval")

    map_files = []
    if "maps" in eval_config:
        map_files = eval_config["maps"]
    else:
        for root, dirs, files in os.walk(maps_eval_dir):
            for file in files:
                if file.endswith(".png"):
                    rel_path = os.path.relpath(os.path.join(root, file), maps_eval_dir)
                    map_files.append(rel_path)

    results = []
    per_type = {}

    for map_file in map_files:
        map_path = os.path.join(maps_eval_dir, map_file)
        env_type = os.path.basename(os.path.dirname(map_path))
        if env_type not in per_type:
            per_type[env_type] = {"explored_rate": [], "travel_distance": [], "success": []}

        env = ExplorationEnv(map_path=map_path)
        obs = env.reset()

        for step in range(128):
            target = get_action(obs)
            if target is None:
                break

            obs, info = env.step(target)
            if info["done"]:
                break

        metrics = env.get_metrics()
        success = 1 if metrics["success"] else 0
        results.append({
            "map_path": map_file,
            "env_type": env_type,
            "success": success,
            "travel_distance": metrics["travel_distance"],
            "explored_rate": metrics["explored_rate"]
        })

        per_type[env_type]["explored_rate"].append(metrics["explored_rate"])
        if success:
            per_type[env_type]["travel_distance"].append(metrics["travel_distance"])
        per_type[env_type]["success"].append(success)

    total_episodes = len(results)
    success_rate = float(np.mean([r["success"] for r in results])) if total_episodes > 0 else 0.0
    explored_rate = float(np.mean([r["explored_rate"] for r in results])) if total_episodes > 0 else 0.0

    successful_distances = [r["travel_distance"] for r in results if r["success"] == 1]
    travel_distance = float(np.mean(successful_distances)) if len(successful_distances) > 0 else 0.0

    per_type_agg = {}
    for env_type, metrics in per_type.items():
        succ_dists = metrics["travel_distance"]
        per_type_agg[env_type] = {
            "explored_rate": float(np.mean(metrics["explored_rate"])) if metrics["explored_rate"] else 0.0,
            "travel_distance": float(np.mean(succ_dists)) if succ_dists else 0.0,
            "success_rate": float(np.mean(metrics["success"])) if metrics["success"] else 0.0
        }

    output_data = {
        "explored_rate": explored_rate,
        "travel_distance": travel_distance,
        "success_rate": success_rate,
        "per_episode": results,
        "per_type": per_type_agg,
        "total_episodes": total_episodes
    }

    with open(args.output, "w") as f:
        json.dump(output_data, f, indent=2)

if __name__ == "__main__":
    main()
